5	package gin
6	
7	import (
8		"fmt"
9		"reflect"
10		"strings"
11	
12		"github.com/gin-gonic/gin/codec/json"
13	)
14	
15	// ErrorType is an unsigned 64-bit error code as defined in the gin spec.
16	type ErrorType uint64
17	
18	const (
19		// ErrorTypeBind is used when Context.Bind() fails.
20		ErrorTypeBind ErrorType = 1 << 63
21		// ErrorTypeRender is used when Context.Render() fails.
22		ErrorTypeRender ErrorType = 1 << 62
23		// ErrorTypePrivate indicates a private error.
24		ErrorTypePrivate ErrorType = 1 << 0
25		// ErrorTypePublic indicates a public error.
26		ErrorTypePublic ErrorType = 1 << 1
27		// ErrorTypeAny indicates any other error.
28		ErrorTypeAny ErrorType = 1<<64 - 1
29	)
30	
31	// Error represents a error's specification.
32	type Error struct {
33		Err  error
34		Type ErrorType
35		Meta any
36	}
37	
38	type errorMsgs []*Error
39	
40	var _ error = (*Error)(nil)
41	
42	// SetType sets the error's type.
43	func (msg *Error) SetType(flags ErrorType) *Error {
44		msg.Type = flags
45		return msg
46	}
47	
48	// SetMeta sets the error's meta data.
49	func (msg *Error) SetMeta(data any) *Error {
50		msg.Meta = data
51		return msg
52	}
53	
54	// JSON creates a properly formatted JSON
55	func (msg *Error) JSON() any {
56		jsonData := H{}
57		if msg.Meta != nil {
58			value := reflect.ValueOf(msg.Meta)
59			switch value.Kind() {
60			case reflect.Struct:
61				return msg.Meta
62			case reflect.Map:
63				for _, key := range value.MapKeys() {
64					jsonData[key.String()] = value.MapIndex(key).Interface()
65				}
66			default:
67				jsonData["meta"] = msg.Meta
68			}
69		}
70		if _, ok := jsonData["error"]; !ok {
71			jsonData["error"] = msg.Error()
72		}
73		return jsonData
74	}
75	
76	// MarshalJSON implements the json.Marshaller interface.
77	func (msg *Error) MarshalJSON() ([]byte, error) {
78		return json.API.Marshal(msg.JSON())
79	}
80	
81	// Error implements the error interface.
82	func (msg Error) Error() string {
83		return msg.Err.Error()
84	}
85	
86	// IsType judges one error.
87	func (msg *Error) IsType(flags ErrorType) bool {
88		return (msg.Type & flags) > 0
89	}
90	
91	// Unwrap returns the wrapped error, to allow interoperability with errors.Is(), errors.As() and errors.Unwrap()
92	func (msg Error) Unwrap() error {
93		return msg.Err
94	}
95	
96	// ByType returns a readonly copy filtered the byte.
97	// ie ByType(gin.ErrorTypePublic) returns a slice of errors with type=ErrorTypePublic.
98	func (a errorMsgs) ByType(typ ErrorType) errorMsgs {
99		if len(a) == 0 {
100			return nil
101		}
102		if typ == ErrorTypeAny {
103			return a
104		}
105		var result errorMsgs
106		for _, msg := range a {
107			if msg.IsType(typ) {
108				result = append(result, msg)
109			}
110		}
111		return result
112	}
113	
114	// Last returns the last error in the slice. It returns nil if the array is empty.
115	// Shortcut for errors[len(errors)-1].
116	func (a errorMsgs) Last() *Error {
117		if length := len(a); length > 0 {
118			return a[length-1]
119		}
120		return nil
121	}
122	
123	// Errors returns an array with all the error messages.
124	// Example:
125	//
126	//	c.Error(errors.New("first"))
127	//	c.Error(errors.New("second"))
128	//	c.Error(errors.New("third"))
129	//	c.Errors.Errors() // == []string{"first", "second", "third"}
130	func (a errorMsgs) Errors() []string {
131		if len(a) == 0 {
132			return nil
133		}
134		errorStrings := make([]string, len(a))
135		for i, err := range a {
136			errorStrings[i] = err.Error()
137		}
138		return errorStrings
139	}
140	
141	func (a errorMsgs) JSON() any {
142		switch length := len(a); length {
143		case 0:
144			return nil
145		case 1:
146			return a.Last().JSON()
147		default:
148			jsonData := make([]any, length)
149			for i, err := range a {
150				jsonData[i] = err.JSON()
151			}
152			return jsonData
153		}
154	}
155	
156	// MarshalJSON implements the json.Marshaller interface.
157	func (a errorMsgs) MarshalJSON() ([]byte, error) {
158		return json.API.Marshal(a.JSON())
159	}
160	
161	func (a errorMsgs) String() string {
162		if len(a) == 0 {
163			return ""
164		}
165		var buffer strings.Builder
166		for i, msg := range a {
167			fmt.Fprintf(&buffer, "Error #%02d: %s\n", i+1, msg.Err)
168			if msg.Meta != nil {
169				fmt.Fprintf(&buffer, "     Meta: %v\n", msg.Meta)
170			}
171		}
172		return buffer.String()
173	}
