26	const (
27		dunno     = "???"
28		stackSkip = 3
29	)
30	
31	// RecoveryFunc defines the function passable to CustomRecovery.
32	type RecoveryFunc func(c *Context, err any)
33	
34	// Recovery returns a middleware that recovers from any panics and writes a 500 if there was one.
35	func Recovery() HandlerFunc {
36		return RecoveryWithWriter(DefaultErrorWriter)
37	}
38	
39	// CustomRecovery returns a middleware that recovers from any panics and calls the provided handle func to handle it.
40	func CustomRecovery(handle RecoveryFunc) HandlerFunc {
41		return RecoveryWithWriter(DefaultErrorWriter, handle)
42	}
43	
44	// RecoveryWithWriter returns a middleware for a given writer that recovers from any panics and writes a 500 if there was one.
45	func RecoveryWithWriter(out io.Writer, recovery ...RecoveryFunc) HandlerFunc {
46		if len(recovery) > 0 {
47			return CustomRecoveryWithWriter(out, recovery[0])
48		}
49		return CustomRecoveryWithWriter(out, defaultHandleRecovery)
50	}
51	
52	// CustomRecoveryWithWriter returns a middleware for a given writer that recovers from any panics and calls the provided handle func to handle it.
53	func CustomRecoveryWithWriter(out io.Writer, handle RecoveryFunc) HandlerFunc {
54		var logger *log.Logger
55		if out != nil {
56			logger = log.New(out, "\n\n\x1b[31m", log.LstdFlags)
57		}
58		return func(c *Context) {
59			defer func() {
60				if rec := recover(); rec != nil {
61					// Check for a broken connection, as it is not really a
62					// condition that warrants a panic stack trace.
63					var isBrokenPipe bool
64					err, ok := rec.(error)
65					if ok {
66						isBrokenPipe = errors.Is(err, syscall.EPIPE) ||
67							errors.Is(err, syscall.ECONNRESET) ||
68							errors.Is(err, http.ErrAbortHandler)
69					}
70					if logger != nil {
71						if isBrokenPipe {
72							logger.Printf("%s\n%s%s", rec, secureRequestDump(c.Request), reset)
73						} else if IsDebugging() {
74							logger.Printf("[Recovery] %s panic recovered:\n%s\n%s\n%s%s",
75								timeFormat(time.Now()), secureRequestDump(c.Request), rec, stack(stackSkip), reset)
76						} else {
77							logger.Printf("[Recovery] %s panic recovered:\n%s\n%s%s",
78								timeFormat(time.Now()), rec, stack(stackSkip), reset)
79						}
80					}
81					if isBrokenPipe {
82						// If the connection is dead, we can't write a status to it.
83						c.Error(err) //nolint: errcheck
84						c.Abort()
85					} else {
86						handle(c, rec)
87					}
88				}
89			}()
90			c.Next()
91		}
92	}
93	
94	// secureRequestDump returns a sanitized HTTP request dump where the Authorization header,
95	// if present, is replaced with a masked value ("Authorization: *") to avoid leaking sensitive credentials.
96	//
97	// Currently, only the Authorization header is sanitized. All other headers and request data remain unchanged.
98	func secureRequestDump(r *http.Request) string {
99		httpRequest, _ := httputil.DumpRequest(r, false)
100		lines := strings.Split(bytesconv.BytesToString(httpRequest), "\r\n")
101		for i, line := range lines {
102			if strings.HasPrefix(line, "Authorization:") {
103				lines[i] = "Authorization: *"
104			}
105		}
106		return strings.Join(lines, "\r\n")
107	}
108	
109	func defaultHandleRecovery(c *Context, _ any) {
110		c.AbortWithStatus(http.StatusInternalServerError)
111	}
112	
113	// stack returns a nicely formatted stack frame, skipping skip frames.
114	func stack(skip int) []byte {
115		buf := new(bytes.Buffer) // the returned data
116		// As we loop, we open files and read them. These variables record the currently
117		// loaded file.
118		var (
119			nLine    string
120			lastFile string
121			err      error
122		)
123		for i := skip; ; i++ { // Skip the expected number of frames
124			pc, file, line, ok := runtime.Caller(i)
125			if !ok {
126				break
127			}
128			// Print this much at least.  If we can't find the source, it won't show.
129			fmt.Fprintf(buf, "%s:%d (0x%x)\n", file, line, pc)
130			if file != lastFile {
131				nLine, err = readNthLine(file, line-1)
132				if err != nil {
133					continue
134				}
135				lastFile = file
136			}
137			fmt.Fprintf(buf, "\t%s: %s\n", function(pc), cmp.Or(nLine, dunno))
138		}
139		return buf.Bytes()
140	}
141	
142	// readNthLine reads the nth line from the file.
143	// It returns the trimmed content of the line if found,
144	// or an empty string if the line doesn't exist.
145	// If there's an error opening the file, it returns the error.
146	func readNthLine(file string, n int) (string, error) {
147		if n < 0 {
148			return "", nil
149		}
150	
151		f, err := os.Open(file)
152		if err != nil {
153			return "", err
154		}
155		defer f.Close()
156	
157		scanner := bufio.NewScanner(f)
158		for i := 0; i < n; i++ {
159			if !scanner.Scan() {
160				return "", nil
161			}
162		}
163	
164		if scanner.Scan() {
165			return strings.TrimSpace(scanner.Text()), nil
166		}
167	
168		return "", nil
169	}
170	
171	// function returns, if possible, the name of the function containing the PC.
172	func function(pc uintptr) string {
173		fn := runtime.FuncForPC(pc)
174		if fn == nil {
175			return dunno
176		}
177		name := fn.Name()
178		// The name includes the path name to the package, which is unnecessary
179		// since the file name is already included.  Plus, it has center dots.
180		// That is, we see
181		//	runtime/debug.*T·ptrmethod
182		// and want
183		//	*T.ptrmethod
184		// Also the package path might contain dot (e.g. code.google.com/...),
185		// so first eliminate the path prefix
186		if lastSlash := strings.LastIndexByte(name, '/'); lastSlash >= 0 {
187			name = name[lastSlash+1:]
188		}
189		if period := strings.IndexByte(name, '.'); period >= 0 {
190			name = name[period+1:]
191		}
192		name = strings.ReplaceAll(name, "·", ".")
193		return name
194	}
195	
196	// timeFormat returns a customized time string for logger.
197	func timeFormat(t time.Time) string {
198		return t.Format("2006/01/02 - 15:04:05")
199	}
