797	// BindUri binds the passed struct pointer using binding.Uri.
798	// It will abort the request with HTTP 400 if any error occurs.
799	func (c *Context) BindUri(obj any) error {
800		if err := c.ShouldBindUri(obj); err != nil {
801			c.AbortWithError(http.StatusBadRequest, err).SetType(ErrorTypeBind) //nolint: errcheck
802			return err
803		}
804		return nil
805	}
