func (msg *Error) JSON() any {
    jsonData := H{}  // H is map[string]any

    if msg.Meta != nil {
        value := reflect.ValueOf(msg.Meta)
        switch value.Kind() {
        case reflect.Struct:
            return msg.Meta  // Return struct directly
        case reflect.Map:
            // Flatten map entries into jsonData
            for _, key := range value.MapKeys() {
                jsonData[key.String()] = value.MapIndex(key).Interface()
            }
        default:
            jsonData["meta"] = msg.Meta  // Wrap other types
        }
    }

    // Ensure "error" key exists
    if _, ok := jsonData["error"]; !ok {
        jsonData["error"] = msg.Error()  // msg.Err.Error()
    }

    return jsonData
}
```

